import { Component, createUniqueId, mergeProps } from 'solid-js';
import type { InputDateProps } from '../input.types';
import { DEFAULT_PROPS } from '../input.utils';
import { InputText } from './input-text';

export const InputDate: Component<InputDateProps> = (p => {
  const id = createUniqueId();
  p = mergeProps({ ...DEFAULT_PROPS, id }, p);
  return (
    <InputText
      {...p}
      type={'date' as 'text'}
      typeOrigin="date"
      maskOptions={void 0}
      allowClear={false}
    />
  );
}) as Component<InputDateProps>;
